input.command:
cd /Users/aleksishmanov/projects/po-helper
for f in docs/superpowers/plans/2026-07-06-daily-review.md docs/superpowers/specs/2026-07-06-daily-review-design.md; do
  perl -i -pe '
    # Finding 1: bare NEXUS/ -> GROUND/NEXUS/ (skip if already GROUND/ or path-prefixed)
    s{(?<!GROUND/)(?<![\w/])NEXUS/(team|risk|commitments)}{GROUND/NEXUS/$1}g;
    # Finding 2: meetings backlink form -> {meeting_notes} (only the ·-separated backlink, not GROUND/PULSE/meetings literal)
    s{· meetings/\{папка\}}{· {meeting_notes}/{папка}}g;
    s{`← C-NNN · meetings/\{папка\}`}{`← C-NNN · {meeting_notes}/{папка}`}g;
    # Finding 3: srok -> due contradictions
    s{срок → due}{срок → в описание задачи (у Backlog.md нет поля `due`)}g;
    s{slipped→сдвинуть due}{slipped→сдвинуть `Срок:` в описании}g;
    s{slipped → сдвинуть due \+ заметка}{slipped → сдвинуть `Срок:` в описании + заметка}g;
    s{`slipped` → сдвинуть due \+ заметка}{`slipped` → сдвинуть `Срок:` в описании + заметка}g;
  ' "$f"
done
echo "=== residual checks ==="
echo "-- bare NEXUS/ --"; grep -rn "NEXUS/" docs/superpowers/*/2026-07-06-daily-review* | grep -v "GROUND/NEXUS" || echo clean
echo "-- meetings/{папка} backlink --"; grep -rn "· meetings/{папка}\|C-NNN · meetings" docs/superpowers/*/2026-07-06-daily-review* || echo clean
echo "-- срок → due --"; grep -rn "срок → due\|сдвинуть due" docs/superpowers/*/2026-07-06-daily-review* || echo clean
